mapper.select:
select count(*)
from chat_session s
left join demo_order o on s.order_id=o.id
where 1=1
and s.user_id=#{s.userId}
and s.status=#{s.status}
and s.channel=#{s.channel}

    and (s.title like concat('%',#{s.keyword},'%')
     or s.current_intent like concat('%',#{s.keyword},'%')
     or o.order_no like concat('%',#{s.keyword},'%'))

select s.*, o.order_no from chat_session s left join demo_order o on s.order_id=o.id where 1=1 and s.user_id=#{s.userId} and s.status=#{s.status} and s.channel=#{s.channel}
and (s.title like concat('%',#{s.keyword},'%') or s.current_intent like concat('%',#{s.keyword},'%') or o.order_no like concat('%',#{s.keyword},'%'))
order by s.updated_at desc, s.id desc

mapper.update:
update chat_session
set user_id=#{userId}, order_id=#{orderId}, title=#{title}, channel=coalesce(#{channel}, 'WEB'),
    status=coalesce(#{status}, 'ACTIVE'), current_intent=#{currentIntent}, summary=#{summary}
where id=#{id}
